def replace_icons(filepath):
  try:
    with open(filepath, 'r', encoding='utf-8') as f:
      content = f.read()

    for metric_id, new_icon in icons.items():
      # For index.html & multi_metric (uses id="val-...")
      pattern1 = r'(<div class="metric-icon">)(<svg.*?</svg>)(</div><div class="metric-info"><span class="metric-value" id="val-' + re.escape(metric_id) + r'")'
      content = re.sub(pattern1, r'\g<1>' + new_icon.replace('\\', '\\\\') + r'\g<3>', content)
      
      # For comparison.html (uses data-metric="...")
      pattern2 = r'(data-metric="' + re.escape(metric_id) + r'"><div class="metric-icon">)(<svg.*?</svg>)(</div>)'
      content = re.sub(pattern2, r'\g<1>' + new_icon.replace('\\', '\\\\') + r'\g<3>', content)

    with open(filepath, 'w', encoding='utf-8') as f:
      f.write(content)
  except Exception as e:
    print(f'Error updating {filepath}: {e}')

for f in html_files:
  replace_icons(f)
